'use client';

import { useState, useRef, useCallback } from 'react';
import { GoogleMap, useJsApiLoader, Marker, Autocomplete } from '@react-google-maps/api';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Loader2 } from 'lucide-react';

const containerStyle = {
  width: '100%',
  height: '100%',
  borderRadius: 'var(--radius)',
};

// Default center (e.g., Bogotá, Colombia)
const defaultCenter = {
  lat: 4.7110,
  lng: -74.0721
};

interface MapSelectorProps {
  onLocationSelect: (address: string) => void;
}

const libraries: "places"[] = ["places"];

export function MapSelector({ onLocationSelect }: MapSelectorProps) {
  const { isLoaded, loadError } = useJsApiLoader({
    googleMapsApiKey: process.env.NEXT_PUBLIC_GOOGLE_MAPS_API_KEY || "",
    libraries,
  });

  const [map, setMap] = useState<google.maps.Map | null>(null);
  const [center, setCenter] = useState(defaultCenter);
  const [markerPosition, setMarkerPosition] = useState<google.maps.LatLngLiteral | null>(null);
  const autocompleteRef = useRef<google.maps.places.Autocomplete | null>(null);

  const onLoad = useCallback(function callback(mapInstance: google.maps.Map) {
    setMap(mapInstance);
  }, []);

  const onUnmount = useCallback(function callback() {
    setMap(null);
  }, []);

  const onPlaceChanged = () => {
    if (autocompleteRef.current) {
      const place = autocompleteRef.current.getPlace();
      if (place.geometry && place.geometry.location) {
        const location = {
          lat: place.geometry.location.lat(),
          lng: place.geometry.location.lng(),
        };
        setCenter(location);
        setMarkerPosition(location);
        map?.panTo(location);
        if (place.formatted_address) {
            onLocationSelect(place.formatted_address);
        }
      }
    }
  };

  const onMapClick = (e: google.maps.MapMouseEvent) => {
    if (e.latLng) {
      const clickedPos = { lat: e.latLng.lat(), lng: e.latLng.lng() };
      setMarkerPosition(clickedPos);
      
      const geocoder = new window.google.maps.Geocoder();
      geocoder.geocode({ location: clickedPos }, (results, status) => {
        if (status === 'OK' && results && results[0]) {
          onLocationSelect(results[0].formatted_address);
        } else {
          console.warn('Geocoder failed due to: ' + status);
        }
      });
    }
  };

  if (loadError) {
    return (
        <div className="flex items-center justify-center h-full text-destructive">
            Error al cargar el mapa. Asegúrate de que la clave de API de Google Maps sea válida.
        </div>
    );
  }

  return isLoaded ? (
    <div className="relative h-full w-full">
      <div className="absolute top-2 left-1/2 -translate-x-1/2 z-10 w-full max-w-md px-4">
        <Autocomplete
          onLoad={(ref) => autocompleteRef.current = ref}
          onPlaceChanged={onPlaceChanged}
        >
          <Input type="text" placeholder="Buscar dirección..." className="w-full shadow-md" />
        </Autocomplete>
      </div>
      <GoogleMap
        mapContainerStyle={containerStyle}
        center={center}
        zoom={12}
        onLoad={onLoad}
        onUnmount={onUnmount}
        onClick={onMapClick}
        options={{
            fullscreenControl: false,
            streetViewControl: false,
            mapTypeControl: false,
            zoomControl: true,
        }}
      >
        {markerPosition && <Marker position={markerPosition} />}
      </GoogleMap>
    </div>
  ) : (
    <div className="flex items-center justify-center h-full">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
        <p className="ml-2">Cargando mapa...</p>
    </div>
  );
}
